---
// OnlineSticker component with improved functionality
---

<!-- Online Visitors Sticker -->
<div class="online-sticker" aria-live="polite" aria-atomic="true">
  <div class="online-sticker__pulse"></div>
  <svg class="online-sticker__icon" width="16" height="16" viewBox="0 0 16 16" fill="none">
    <circle cx="8" cy="8" r="7" stroke="currentColor" stroke-width="1.5" opacity="0.7"></circle>
    <circle cx="8" cy="8" r="2" fill="currentColor"></circle>
  </svg>
  <span class="online-sticker__text">Сейчас на сайте:</span>
  <span class="online-sticker__count">5</span>
  <span class="online-sticker__suffix">человек</span>
</div>

<script>
  class OnlineSticker {
    constructor() {
      this.element = document.querySelector('.online-sticker');
      this.countElement = document.querySelector('.online-sticker__count');
      this.minVisitors = 2;
      this.maxVisitors = 7;
      this.showDuration = 3000; // 3 seconds
      this.hideDuration = 45000; // 45 seconds
      this.isVisible = false;

      this.init();
    }

    init() {
      // Initial delay before first show
      setTimeout(() => {
        this.show();
        this.startCycle();
      }, 5000); // Start after 5 seconds
    }

    getRandomCount() {
      return (
        Math.floor(Math.random() * (this.maxVisitors - this.minVisitors + 1)) + this.minVisitors
      );
    }

    updateCount() {
      const newCount = this.getRandomCount();

      // Add animation class
      this.countElement?.classList.add('online-sticker__count--updating');

      // Update count
      setTimeout(() => {
        if (this.countElement) {
          this.countElement.textContent = newCount.toString();
        }
      }, 150);

      // Remove animation class
      setTimeout(() => {
        this.countElement?.classList.remove('online-sticker__count--updating');
      }, 300);
    }

    show() {
      if (!this.element || this.isVisible) return;

      this.updateCount();
      this.element.classList.add('online-sticker--visible');
      this.isVisible = true;

      // Hide after duration
      setTimeout(() => {
        this.hide();
      }, this.showDuration);
    }

    hide() {
      if (!this.element || !this.isVisible) return;

      this.element.classList.remove('online-sticker--visible');
      this.isVisible = false;
    }

    startCycle() {
      setInterval(() => {
        if (!this.isVisible) {
          this.show();
        }
      }, this.hideDuration + this.showDuration);
    }

    // Check if user is scrolling near bottom
    handleScroll() {
      const scrollPosition = window.scrollY + window.innerHeight;
      const documentHeight = document.documentElement.scrollHeight;

      // Hide if user is near footer
      if (documentHeight - scrollPosition < 200) {
        this.hide();
      }
    }
  }

  // Initialize when DOM is ready
  document.addEventListener('DOMContentLoaded', () => {
    const sticker = new OnlineSticker();

    // Optional: Hide when scrolling near footer
    let scrollTimeout;
    window.addEventListener('scroll', () => {
      clearTimeout(scrollTimeout);
      scrollTimeout = setTimeout(() => {
        sticker.handleScroll();
      }, 100);
    });
  });

  // Analytics tracking (optional)
  document.addEventListener('DOMContentLoaded', () => {
    const stickerElement = document.querySelector('.online-sticker');

    stickerElement?.addEventListener('transitionend', (e) => {
      if (
        e.propertyName === 'opacity' &&
        stickerElement.classList.contains('online-sticker--visible')
      ) {
        // Track sticker display
        if (typeof gtag !== 'undefined') {
          gtag('event', 'online_sticker_shown', {
            event_category: 'engagement',
            event_label: 'sticker_display',
          });
        }
      }
    });
  });
</script>

import { z } from 'zod';

const envSchema = z.object({
  PUBLIC_SITE_URL: z.string().url(),
  PUBLIC_SITE_PHONE: z.string(),
  PUBLIC_SITE_EMAIL: z.string().email(),
  BITRIX24_WEBHOOK_URL: z.string().url(),
  PUBLIC_GA_ID: z.string().optional(),
  PUBLIC_YM_ID: z.string().optional(),
  PUBLIC_ASTRO_TOOLBAR: z
    .enum(['true', 'false'])
    .transform((value) => value === 'true')
    .optional(),
});

export const validateEnv = (): z.infer<typeof envSchema> => {
  try {
    return envSchema.parse(process.env);
  } catch (error) {
    console.error('Environment validation failed:', error);
    process.exit(1);
  }
};

// Environment validation utility
export function validateEnvironment(): boolean {
  const requiredVars: string[] = [
    'BITRIX24_WEBHOOK_URL',
    'PUBLIC_SITE_URL',
    'PUBLIC_SITE_PHONE',
    'PUBLIC_SITE_EMAIL',
  ];

  const missingVars: string[] = requiredVars.filter((varName) => !process.env[varName]);

  if (missingVars.length > 0) {
    console.warn('Missing required environment variables:', missingVars);
    return false;
  }

  // Validate URL format
  try {
    if (process.env.PUBLIC_SITE_URL) {
      new URL(process.env.PUBLIC_SITE_URL);
    }
    if (process.env.BITRIX24_WEBHOOK_URL) {
      new URL(process.env.BITRIX24_WEBHOOK_URL);
    }
  } catch (error: unknown) {
    console.warn('Invalid URL in environment variables', error);
    return false;
  }

  // Validate email format
  if (process.env.PUBLIC_SITE_EMAIL) {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(process.env.PUBLIC_SITE_EMAIL)) {
      console.warn('Invalid email format in PUBLIC_SITE_EMAIL');
      return false;
    }
  }

  // Validate phone format
  if (process.env.PUBLIC_SITE_PHONE) {
    const phoneRegex = /^(\+7|8)[\s\-]?\(?\d{3}\)?[\s\-]?\d{3}[\s\-]?\d{2}[\s\-]?\d{2}$/;
    if (!phoneRegex.test(process.env.PUBLIC_SITE_PHONE)) {
      console.warn('Invalid phone format in PUBLIC_SITE_PHONE');
      return false;
    }
  }

  console.log('Environment validation passed');
  return true;
}

// Analytics integration script for ZeroDolg Astro project
// Based on the original project's analytics implementation

// Configuration - these should be set in environment variables
const CONFIG = {
  YANDEX_METRIKA_ID: import.meta.env.PUBLIC_YM_ID,
  GOOGLE_ANALYTICS_ID: import.meta.env.PUBLIC_GA_ID,
  BITRIX24_WEBHOOK_URL: import.meta.env.BITRIX24_WEBHOOK_URL,
  DEBUG: import.meta.env.DEBUG === 'true' || false,
};

// Debug logging function
function debugLog(message, data) {
  if (CONFIG.DEBUG) {
    console.log(`[Analytics] ${message}`, data || '');
  }
}

// Initialize Yandex Metrika
function initYandexMetrika() {
  if (!CONFIG.YANDEX_METRIKA_ID) {
    debugLog('Yandex Metrika ID not configured');
    return;
  }

  // Load Yandex Metrika script
  (function (m, e, t, r, i, k, a) {
    m[i] =
      m[i] ||
      function () {
        (m[i].a = m[i].a || []).push(arguments);
      };
    m[i].l = 1 * new Date();
    for (let j = 0; j < document.scripts.length; j++) {
      if (document.scripts[j].src === r) {
        return;
      }
    }
    ((k = e.createElement(t)),
      (a = e.getElementsByTagName(t)[0]),
      (k.async = 1),
      (k.src = r),
      a.parentNode.insertBefore(k, a));
  })(window, document, 'script', 'https://mc.yandex.ru/metrika/tag.js', 'ym');

  // Initialize with configuration
  ym(CONFIG.YANDEX_METRIKA_ID, 'init', {
    defer: true,
    clickmap: true,
    trackLinks: true,
    accurateTrackBounce: true,
    webvisor: true,
    ecommerce: 'dataLayer',
    triggerEvent: true,
    params: {
      page_url: window.location.href,
      page_ref: document.referrer,
      init_utc_timestamp: new Date().toISOString(),
      page_load_utc: new Date().getTime(),
      timezone_offset: new Date().getTimezoneOffset(),
      timezone_name: Intl.DateTimeFormat().resolvedOptions().timeZone,
      user_agent: navigator.userAgent,
      screen_resolution: `${screen.width}x${screen.height}`,
      viewport_size: `${window.innerWidth}x${window.innerHeight}`,
      page_title: document.title,
    },
  });

  debugLog('Yandex Metrika initialized');
}

// Initialize Google Analytics
function initGoogleAnalytics() {
  if (!CONFIG.GOOGLE_ANALYTICS_ID) {
    debugLog('Google Analytics ID not configured');
    return;
  }

  // Load gtag.js
  const script = document.createElement('script');
  script.async = true;
  script.src = `https://www.googletagmanager.com/gtag/js?id=${CONFIG.GOOGLE_ANALYTICS_ID}`;
  document.head.appendChild(script);

  // Initialize
  window.dataLayer = window.dataLayer || [];
  function gtag() {
    dataLayer.push(arguments);
  }
  window.gtag = gtag;
  gtag('js', new Date());
  gtag('config', CONFIG.GOOGLE_ANALYTICS_ID, {
    send_page_view: true,
    anonymize_ip: true,
    cookie_flags: 'SameSite=None;Secure',
  });

  debugLog('Google Analytics initialized');
}

// Track scroll depth
function trackScrollDepth() {
  let maxScroll = 0;
  const scrollDepths = [25, 50, 75, 100];
  const trackedDepths = [];

  window.addEventListener('scroll', () => {
    const scrollPercent = Math.round(
      (window.scrollY / (document.documentElement.scrollHeight - window.innerHeight)) * 100
    );

    if (scrollPercent > maxScroll) {
      maxScroll = scrollPercent;

      scrollDepths.forEach((depth) => {
        if (scrollPercent >= depth && !trackedDepths.includes(depth)) {
          trackedDepths.push(depth);

          // Yandex.Metrika
          if (typeof ym !== 'undefined') {
            ym(CONFIG.YANDEX_METRIKA_ID, 'reachGoal', 'scroll_depth', {
              depth: depth,
            });
          }

          // Google Analytics
          if (typeof gtag !== 'undefined') {
            gtag('event', 'scroll', {
              event_category: 'engagement',
              event_label: `${depth}%`,
              value: depth,
            });
          }

          debugLog('Scroll depth tracked:', `${depth}%`);
        }
      });
    }
  });
}

// Track phone clicks
function trackPhoneClicks() {
  document.addEventListener(
    'click',
    (e) => {
      const link = e.target.closest('a[href^="tel:"]');
      if (link) {
        const phoneNumber = link.href.replace('tel:', '');

        // Yandex.Metrika
        if (typeof ym !== 'undefined') {
          ym(CONFIG.YANDEX_METRIKA_ID, 'reachGoal', 'phone_click', {
            phone: phoneNumber,
          });
        }

        // Google Analytics
        if (typeof gtag !== 'undefined') {
          gtag('event', 'phone_click', {
            event_category: 'contact',
            event_label: phoneNumber,
          });
        }

        debugLog('Phone click tracked:', phoneNumber);
      }
    },
    true
  );
}

// Track form submissions
function trackFormSubmissions() {
  document.addEventListener('submit', (e) => {
    const form = e.target;
    if (form && form.tagName === 'FORM') {
      const formId = form.id || 'unknown';
      const formClass = form.className || 'unknown';

      // Yandex.Metrika
      if (typeof ym !== 'undefined') {
        ym(CONFIG.YANDEX_METRIKA_ID, 'reachGoal', 'form_submit_direct', {
          form_id: formId,
          form_class: formClass,
        });
      }

      // Google Analytics
      if (typeof gtag !== 'undefined') {
        gtag('event', 'form_submit_direct', {
          event_category: 'engagement',
          event_label: formId,
        });
      }

      debugLog('Form submission tracked:', { id: formId, class: formClass });
    }
  });
}

// Track CTA clicks
function trackCTAClicks() {
  document.addEventListener(
    'click',
    (e) => {
      const button = e.target.closest(
        '.cta-primary, .btn-primary, .cta-button, button[type="submit"]'
      );
      if (button) {
        const buttonText = button.textContent.trim();
        const buttonLocation = button.closest('section')?.className || 'unknown';

        // Yandex.Metrika
        if (typeof ym !== 'undefined') {
          ym(CONFIG.YANDEX_METRIKA_ID, 'reachGoal', 'cta_click', {
            button_text: buttonText,
            location: buttonLocation,
          });
        }

        // Google Analytics
        if (typeof gtag !== 'undefined') {
          gtag('event', 'cta_click', {
            event_category: 'engagement',
            event_label: buttonText,
            event_location: buttonLocation,
          });
        }

        debugLog('CTA click tracked:', { text: buttonText, location: buttonLocation });
      }
    },
    true
  );
}

// Main initialization function
function initAnalytics() {
  // Initialize analytics services
  initYandexMetrika();
  initGoogleAnalytics();

  // Set up event tracking
  trackScrollDepth();
  trackPhoneClicks();
  trackFormSubmissions();
  trackCTAClicks();

  // Expose analytics API for manual tracking
  window.ZeroDolgAnalytics = {
    // Track custom event
    trackEvent: function (eventName, parameters) {
      parameters = parameters || {};

      // Yandex.Metrika
      if (typeof ym !== 'undefined' && CONFIG.YANDEX_METRIKA_ID) {
        ym(CONFIG.YANDEX_METRIKA_ID, 'reachGoal', eventName, parameters);
      }

      // Google Analytics
      if (typeof gtag !== 'undefined' && CONFIG.GOOGLE_ANALYTICS_ID) {
        gtag(
          'event',
          eventName,
          Object.assign(
            {
              event_category: 'custom',
            },
            parameters
          )
        );
      }

      debugLog('Custom event tracked:', { event: eventName, parameters: parameters });
    },

    // Enable/disable debug mode
    setDebug: function (enabled) {
      CONFIG.DEBUG = enabled;
      debugLog('Debug mode:', enabled ? 'enabled' : 'disabled');
    },

    // Get current config
    getConfig: function () {
      return CONFIG;
    },
  };

  debugLog('Analytics initialized');
}

// Initialize when DOM is ready
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', initAnalytics);
} else {
  // DOM is already ready
  initAnalytics();
}

export { initAnalytics };
export default initAnalytics;

// For backward compatibility with Layout.astro
export const injectAnalytics = initAnalytics;

