// Calculator.astro - Calculator component with original design
export interface Props {
  title?: string;
  subtitle?: string;
}

const {
  title = 'Рассчитайте стоимость банкротства',
  subtitle = 'Узнайте точную сумму за 1 минуту',
} = Astro.props;
---

<section class="py-16 md:py-24 bg-gradient-to-b from-blue-50 to-indigo-50" id="calculator">
  <div class="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
    <header class="text-center mb-12 md:mb-16">
      <h2 id="calculator-title" class="text-3xl md:text-4xl font-bold text-gray-900 mb-4">
        {title}
      </h2>
      <p class="text-xl text-gray-600 max-w-3xl mx-auto">{subtitle}</p>
    </header>

    <form
      class="bg-white rounded-2xl shadow-lg p-6 md:p-8 max-w-3xl mx-auto"
      role="form"
      aria-labelledby="calculator-title"
    >
      <fieldset class="space-y-6">
        <legend class="sr-only">Параметры для расчета стоимости банкротства</legend>

        <div class="space-y-2">
          <label for="debt-amount" class="block text-lg font-medium text-gray-900"
            >Сумма долга</label
          >
          <select
            id="debt-amount"
            class="calc-select w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors text-gray-900 bg-white"
            aria-describedby="debt-help"
          >
            <option value="">Выберите сумму долга</option>
            <option value="under-300k">До 300 000 ₽</option>
            <option value="300k-1m">От 300 000 ₽ до 1 млн ₽</option>
            <option value="1m-3m">От 1 млн ₽ до 3 млн ₽</option>
            <option value="3m-5m">От 3 млн ₽ до 5 млн ₽</option>
            <option value="5m-10m">От 5 млн ₽ до 10 млн ₽</option>
            <option value="over-10m">Свыше 10 млн ₽</option>
          </select>
          <small id="debt-help" class="block text-sm text-gray-500"
            >Укажите общую сумму ваших долгов</small
          >
        </div>

        <div class="space-y-2">
          <label for="property" class="block text-lg font-medium text-gray-900"
            >Есть ли имущество?</label
          >
          <select
            id="property"
            class="calc-select w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors text-gray-900 bg-white"
            aria-describedby="property-help"
          >
            <option value="">Выберите вариант</option>
            <option value="no-property">Нет имущества</option>
            <option value="property-no-equity">Есть имущество без залогов</option>
            <option value="property-with-equity">Есть имущество с залогами</option>
          </select>
          <small id="property-help" class="block text-sm text-gray-500">
            Укажите наличие имущества, которое может быть реализовано
          </small>
        </div>

        <div class="space-y-2">
          <label for="employment" class="block text-lg font-medium text-gray-900"
            >Трудоустройство</label
          >
          <select
            id="employment"
            class="calc-select w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors text-gray-900 bg-white"
            aria-describedby="employment-help"
          >
            <option value="">Выберите статус</option>
            <option value="employed">Трудоустроен</option>
            <option value="unemployed">Безработный</option>
            <option value="pensioner">Пенсионер</option>
            <option value="invalid">Инвалид</option>
            <option value="entrepreneur">ИП</option>
          </select>
          <small id="employment-help" class="block text-sm text-gray-500">
            Укажите ваш текущий статус трудоустройства
          </small>
        </div>

        <button
          type="button"
          class="calc-submit w-full py-4 px-6 bg-blue-600 text-white rounded-lg hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 transition-colors duration-200 font-bold text-lg flex items-center justify-center"
          data-action="calculate"
        >
          <span>Рассчитать стоимость</span>
          <span class="ml-2 loader hidden">
            <svg
              class="animate-spin h-5 w-5 text-white"
              viewBox="0 0 50 50"
              aria-label="Загрузка"
              role="status"
            >
              <circle cx="25" cy="25" r="20" fill="none" stroke-width="5"></circle>
            </svg>
          </span>
        </button>
      </fieldset>

      <div class="calc-result hidden mt-8" aria-live="polite">
        <div class="bg-gradient-to-br from-blue-50 to-indigo-50 rounded-xl p-6">
          <div
            class="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-6"
          >
            <div>
              <h3 class="text-2xl font-bold text-gray-900 mb-2">Ваш персональный расчет готов!</h3>
              <div
                class="calc-badge inline-flex items-center px-3 py-1 bg-blue-500 text-white text-sm font-semibold rounded-full"
              >
              </div>
            </div>
          </div>

          <div class="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
            <div
              class="result-card primary bg-white rounded-lg p-4 text-center border border-gray-200"
            >
              <div class="text-gray-600 mb-1">Стоимость под ключ</div>
              <div class="result-value text-2xl font-bold text-gray-900 mb-1">0 ₽</div>
              <div class="text-sm text-gray-500">или 0 ₽/мес</div>
            </div>
            <div class="result-card bg-white rounded-lg p-4 text-center border border-gray-200">
              <div class="text-gray-600 mb-1">Срок процедуры</div>
              <div class="result-value text-2xl font-bold text-gray-900 mb-1">0 мес</div>
              <div class="text-sm text-gray-500">полное списание долгов</div>
            </div>
            <div
              class="result-card success bg-white rounded-lg p-4 text-center border border-gray-200"
            >
              <div class="text-gray-600 mb-1">Ваша экономия</div>
              <div class="result-value text-2xl font-bold text-gray-900 mb-1">0 ₽</div>
              <div class="text-sm text-gray-500">0% от суммы долга</div>
            </div>
          </div>

          <div class="result-features mb-6">
            <h4 class="text-lg font-semibold text-gray-900 mb-3">Что входит в стоимость:</h4>
            <ul class="space-y-2">
              <li class="flex items-start">
                <svg
                  class="w-5 h-5 text-green-500 flex-shrink-0 mt-0.5 mr-2"
                  viewBox="0 0 24 24"
                  fill="none"
                  stroke="currentColor"
                  stroke-width="2"
                >
                  <path d="M20 6L9 17l-5-5"></path>
                </svg>
                <span>Полная подготовка документов</span>
              </li>
              <li class="flex items-start">
                <svg
                  class="w-5 h-5 text-green-500 flex-shrink-0 mt-0.5 mr-2"
                  viewBox="0 0 24 24"
                  fill="none"
                  stroke="currentColor"
                  stroke-width="2"
                >
                  <path d="M20 6L9 17l-5-5"></path>
                </svg>
                <span>Подача заявления в суд</span>
              </li>
              <li class="flex items-start">
                <svg
                  class="w-5 h-5 text-green-500 flex-shrink-0 mt-0.5 mr-2"
                  viewBox="0 0 24 24"
                  fill="none"
                  stroke="currentColor"
                  stroke-width="2"
                >
                  <path d="M20 6L9 17l-5-5"></path>
                </svg>
                <span>Представительство на всех заседаниях</span>
              </li>
              <li class="flex items-start">
                <svg
                  class="w-5 h-5 text-green-500 flex-shrink-0 mt-0.5 mr-2"
                  viewBox="0 0 24 24"
                  fill="none"
                  stroke="currentColor"
                  stroke-width="2"
                >
                  <path d="M20 6L9 17l-5-5"></path>
                </svg>
                <span>Работа с финансовым управляющим</span>
              </li>
              <li class="flex items-start">
                <svg
                  class="w-5 h-5 text-green-500 flex-shrink-0 mt-0.5 mr-2"
                  viewBox="0 0 24 24"
                  fill="none"
                  stroke="currentColor"
                  stroke-width="2"
                >
                  <path d="M20 6L9 17l-5-5"></path>
                </svg>
                <span>Полное сопровождение до списания</span>
              </li>
            </ul>
          </div>

          <div class="result-actions mb-4">
            <button
              type="button"
              class="result-btn w-full py-3 px-6 bg-blue-600 text-white rounded-lg hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 transition-colors duration-200 font-medium flex items-center justify-center"
              data-modal-trigger="callback"
            >
              Получить консультацию
            </button>
          </div>

          <p class="text-xs text-gray-500 text-center">
            Расчет является ориентировочным. Точную стоимость определит юрист после анализа вашей
            ситуации.
          </p>
        </div>
      </div>
    </form>
  </div>
</section>

<script>
  // Global analytics types
  declare global {
    interface Window {
      gtag: (...args: any[]) => void;
    }
  }

  // Calculator logic
  class BankruptcyCalculator {
    constructor() {
      this.form = document.querySelector('form');
      this.resultDiv = document.querySelector('.calc-result');
      this.submitBtn = document.querySelector('.calc-submit');

      if (this.form) {
        this.init();
      }
    }

    init() {
      this.form.addEventListener('submit', (e) => this.handleSubmit(e));

      // Add change listeners to update button state
      const selects = this.form.querySelectorAll('select');
      selects.forEach((select) => {
        select.addEventListener('change', () => this.checkFormValidity());
      });
    }

    checkFormValidity() {
      const selects = this.form.querySelectorAll('select');
      const allSelected = Array.from(selects).every((select) => select.value !== '');

      if (this.submitBtn) {
        this.submitBtn.disabled = !allSelected;
      }
    }

    handleSubmit(e) {
      e.preventDefault();

      const formData = new FormData(this.form);
      const data = {
        debtAmount: formData.get('debtAmount'),
        hasProperty: formData.get('hasProperty'),
        employmentStatus: formData.get('employmentStatus'),
      };

      // Calculate the cost based on inputs
      const result = this.calculateCost(data);

      // Display the result
      this.displayResult(result);

      // Analytics
      if (typeof gtag !== 'undefined') {
        gtag('event', 'calculator_completed', {
          event_category: 'engagement',
          event_label: 'bankruptcy_calculator',
          value: result.price,
        });
      }
    }

    calculateCost(data) {
      let basePrice = 40000; // Base price
      let monthlyPayment = 5000; // Base monthly payment
      let duration = 8; // Months
      let complexity = 'standard';

      // Adjust based on debt amount
      switch (data.debtAmount) {
        case '100-300':
          basePrice = 35000;
          monthlyPayment = 4500;
          break;
        case '300-500':
          basePrice = 40000;
          monthlyPayment = 5000;
          break;
        case '500-1000':
          basePrice = 45000;
          monthlyPayment = 5500;
          complexity = 'medium';
          break;
        case '1000+':
          basePrice = 50000;
          monthlyPayment = 6000;
          complexity = 'complex';
          duration = 10;
          break;
      }

      // Adjust based on property
      switch (data.hasProperty) {
        case 'none':
          basePrice -= 5000;
          duration = 6;
          complexity = 'simple';
          break;
        case 'apartment':
          // No adjustment for single property
          break;
        case 'multiple':
          basePrice += 10000;
          duration = 12;
          complexity = 'complex';
          break;
      }

      // Adjust based on employment
      switch (data.employmentStatus) {
        case 'unemployed':
          basePrice -= 3000;
          monthlyPayment -= 500;
          break;
        case 'pension':
          basePrice -= 2000;
          monthlyPayment -= 300;
          break;
        case 'business':
          basePrice += 5000;
          complexity = 'complex';
          break;
      }

      // Calculate savings
      const averageDebt = this.getAverageDebt(data.debtAmount);
      const savings = averageDebt - basePrice;
      const savingsPercent = Math.round((savings / averageDebt) * 100);

      return {
        price: basePrice,
        monthlyPayment: monthlyPayment,
        duration: duration,
        complexity: complexity,
        savings: savings,
        savingsPercent: savingsPercent,
        debtAmount: averageDebt,
      };
    }

    getAverageDebt(range) {
      switch (range) {
        case '100-300':
          return 200000;
        case '300-500':
          return 400000;
        case '500-1000':
          return 750000;
        case '1000+':
          return 1500000;
        default:
          return 500000;
      }
    }

    displayResult(result) {
      const complexityText = {
        simple: 'Простая процедура',
        standard: 'Стандартная процедура',
        medium: 'Процедура средней сложности',
        complex: 'Сложная процедура',
      };

      this.resultDiv.innerHTML = `
        <div class="calculator__result-content">
          <div class="calculator__result-header">
            <h3 class="calculator__result-title">Ваш персональный расчет готов!</h3>
            <div class="calculator__result-badge">${complexityText[result.complexity]}</div>
          </div>
          
          <div class="calculator__result-grid">
            <div class="calculator__result-card calculator__result-card--primary">
              <div class="calculator__result-label">Стоимость под ключ</div>
              <div class="calculator__result-value">${result.price.toLocaleString('ru-RU')} ₽</div>
              <div class="calculator__result-note">или ${result.monthlyPayment.toLocaleString('ru-RU')} ₽/мес</div>
            </div>
            
            <div class="calculator__result-card">
              <div class="calculator__result-label">Срок процедуры</div>
              <div class="calculator__result-value">${result.duration} мес</div>
              <div class="calculator__result-note">полное списание долгов</div>
            </div>
            
            <div class="calculator__result-card calculator__result-card--success">
              <div class="calculator__result-label">Ваша экономия</div>
              <div class="calculator__result-value">${result.savings.toLocaleString('ru-RU')} ₽</div>
              <div class="calculator__result-note">${result.savingsPercent}% от суммы долга</div>
            </div>
          </div>
          
          <div class="calculator__result-features">
            <h4 class="calculator__result-features-title">Что входит в стоимость:</h4>
            <ul class="calculator__result-features-list">
              <li>Полное юридическое сопровождение</li>
              <li>Подготовка всех документов</li>
              <li>Представительство в суде</li>
              <li>Работа с кредиторами</li>
              <li>Гарантия результата по договору</li>
            </ul>
          </div>
          
          <div class="calculator__result-actions">
            <button type="button" class="btn btn--primary btn--large calculator__result-btn" data-modal-trigger="callback">
              Получить консультацию бесплатно
            </button>
            <p class="calculator__result-disclaimer">
              Точная стоимость определяется после анализа вашей ситуации
            </p>
          </div>
        </div>
      `;

      // Show result with animation
      this.resultDiv.hidden = false;
      this.resultDiv.scrollIntoView({ behavior: 'smooth', block: 'nearest' });

      // Add click handler for consultation button
      const consultBtn = this.resultDiv.querySelector('[data-modal-trigger="callback"]');
      if (consultBtn) {
        consultBtn.addEventListener('click', () => {
          // Trigger modal or scroll to form
          const modal = document.querySelector('#callback-modal');
          if (modal) {
            modal.classList.add('modal--active');
          } else {
            // Fallback: scroll to CTA section
            const ctaSection = document.querySelector('#cta, .cta');
            if (ctaSection) {
              ctaSection.scrollIntoView({ behavior: 'smooth' });
            }
          }
        });
      }
    }
  }

  // Initialize calculator when DOM is ready
  document.addEventListener('DOMContentLoaded', () => {
    new BankruptcyCalculator();
  });
</script>

import { createContext } from 'preact';
import { useContext, useState, useCallback } from 'preact/hooks';

interface ModalContextType {
  activeModal: string | null;
  openModal: (modalId: string) => void;
  closeModal: () => void;
  closeAllModals: () => void;
}

const ModalContext = createContext<ModalContextType | undefined>(undefined);

export const ModalProvider = ({ children }: { children: import('preact').ComponentChildren }) => {
  const [activeModal, setActiveModal] = useState<string | null>(null);

  const openModal = useCallback((modalId: string) => {
    setActiveModal(modalId);
  }, []);

  const closeModal = useCallback(() => {
    setActiveModal(null);
  }, []);

  const closeAllModals = useCallback(() => {
    setActiveModal(null);
  }, []);

  return (
    <ModalContext.Provider value={{ activeModal, openModal, closeModal, closeAllModals }}>
      {children}
    </ModalContext.Provider>
  );
};

export const useModal = () => {
  const context = useContext(ModalContext);
  if (context === undefined) {
    throw new Error('useModal must be used within a ModalProvider');
  }
  return context;
};

import { useEffect } from 'preact/hooks';

/**
 * Unified Modal Manager Component
 * Handles both declarative modals (defined as components) and
 * imperative modals (created dynamically with JavaScript)
 */
class UnifiedModalManager {
  private activeModal: HTMLElement | null = null;
  private focusedElementBeforeModal: HTMLElement | null = null;
  private dynamicModals: Set<HTMLElement> = new Set();
  private modalTypeMap: Map<string, string> = new Map(); // Map of modal IDs to their types

  init(): void {
    console.log('[ModalManager] Starting initialization');
    // Setup event delegation for modal triggers
    document.addEventListener('click', this.handleTriggerClick.bind(this));
    console.log('[ModalManager] Click event listener added to document');

    // Setup ESC key handling
    document.addEventListener('keydown', this.handleEscKey.bind(this));

    // Setup hash change handling for direct modal opening
    window.addEventListener('hashchange', this.checkHashForModal.bind(this));

    // Check for hash on initial load
    this.checkHashForModal();

    // Setup public API
    window.modalManager = {
      open: this.openModal.bind(this),
      close: this.closeModal.bind(this),
      closeAll: this.closeAllModals.bind(this),
    };
    console.log('[ModalManager] Global API window.modalManager set up');
    console.log('[ModalManager] Initialization completed');
  }

  private handleTriggerClick(e: Event): void {
    console.log('[ModalManager] handleTriggerClick called');
    const target = e.target as HTMLElement;
    const trigger = target.closest('[data-modal]') as HTMLElement;
    console.log('[ModalManager] Trigger element found:', trigger);

    if (trigger) {
      e.preventDefault();
      const modalId = trigger.getAttribute('data-modal');
      const modalType = trigger.getAttribute('data-modal-type');
      console.log('[ModalManager] Modal attributes - id:', modalId, 'type:', modalType);

      if (modalId) {
        // Store the modal type for future reference
        if (modalType) {
          this.modalTypeMap.set(modalId, modalType);
          console.log('[ModalManager] Storing modal type mapping:', modalId, '->', modalType);
          console.log('[ModalManager] Creating dynamic modal');
          this.createDynamicModal(modalId, modalType);
        }
        console.log('[ModalManager] Opening modal');
        this.openModal(modalId);
      }
    }

    // Handle close buttons
    const closeBtn = target.closest('[data-modal-close]') as HTMLElement;
    if (closeBtn) {
      e.preventDefault();
      const modal = closeBtn.closest('[data-modal-container]') as HTMLElement;
      if (modal) {
        this.closeModal(modal);
      } else {
        // For dynamically created modals
        const dynamicModal = closeBtn.closest('.modal') as HTMLElement;
        if (dynamicModal) {
          this.closeDynamicModal(dynamicModal);
        }
      }
    }

    // Handle overlay clicks
    const overlay = target.closest('.modal__overlay') as HTMLElement;
    if (overlay) {
      const modal = overlay.parentElement as HTMLElement;
      if (modal && modal.hasAttribute('data-modal-container')) {
        this.closeModal(modal);
      } else if (modal && modal.classList.contains('modal')) {
        this.closeDynamicModal(modal);
      }
    }
  }

  private handleEscKey(e: KeyboardEvent): void {
    if (e.key === 'Escape' && this.activeModal) {
      this.closeModal();
    }
  }

  /**
   * Open a modal by ID
   */
  openModal(modalId: string): void {
    console.log('[ModalManager] openModal called with modalId:', modalId);
    // First check for declarative modals
    const modal = document.querySelector(`[data-modal-container="${modalId}"]`) as HTMLElement;
    if (modal) {
      console.log('[ModalManager] Found declarative modal, activating');
      this.activateModal(modal);
      return;
    }

    // Then check for dynamic modals
    const dynamicModal = document.querySelector(
      `.modal[data-dynamic-id="${modalId}"]`
    ) as HTMLElement;
    if (dynamicModal) {
      console.log('[ModalManager] Found dynamic modal, activating');
      this.activateModal(dynamicModal);
      return;
    }

    // If no existing modal found, check if we know what type of modal to create
    const modalType = this.modalTypeMap.get(modalId);
    if (modalType) {
      console.log(
        `[ModalManager] Creating dynamic modal for id "${modalId}" with type "${modalType}"`
      );
      this.createDynamicModal(modalId, modalType);
      // Try to find and activate the newly created modal
      const newDynamicModal = document.querySelector(
        `.modal[data-dynamic-id="${modalId}"]`
      ) as HTMLElement;
      if (newDynamicModal) {
        console.log('[ModalManager] Found newly created dynamic modal, activating');
        this.activateModal(newDynamicModal);
        return;
      }
    }

    console.warn(`Modal with id "${modalId}" not found and no type mapping available`);
  }

  /**
   * Activate a modal (both declarative and dynamic)
   */
  private activateModal(modal: HTMLElement): void {
    console.log('[ModalManager] activateModal called with modal:', modal);
    // Store the currently focused element
    this.focusedElementBeforeModal = document.activeElement as HTMLElement;

    // Open modal
    modal.setAttribute('data-open', 'true');
    modal.setAttribute('aria-hidden', 'false');
    document.body.classList.add('modal-open');
    this.activeModal = modal;

    // Focus management
    const firstFocusable = modal.querySelector(
      'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
    ) as HTMLElement;

    if (firstFocusable) {
      setTimeout(() => firstFocusable.focus(), 100);
    }

    // Trap focus within modal
    this.trapFocus(modal);

    // Fire custom event
    const modalId =
      modal.getAttribute('data-modal-container') || modal.getAttribute('data-dynamic-id') || '';
    modal.dispatchEvent(new CustomEvent('modal:opened', { detail: { modalId } }));
    console.log('[ModalManager] Modal activated successfully');
  }

  /**
   * Close a specific modal or the active modal
   */
  closeModal(modal?: HTMLElement): void {
    const targetModal = modal || this.activeModal;
    if (!targetModal) return;

    // Close modal
    targetModal.setAttribute('data-open', 'false');
    targetModal.setAttribute('aria-hidden', 'true');
    document.body.classList.remove('modal-open');

    // Restore focus
    if (this.focusedElementBeforeModal) {
      this.focusedElementBeforeModal.focus();
      this.focusedElementBeforeModal = null;
    }

    // Fire custom event
    const modalId =
      targetModal.getAttribute('data-modal-container') ||
      targetModal.getAttribute('data-dynamic-id') ||
      '';
    targetModal.dispatchEvent(new CustomEvent('modal:closed', { detail: { modalId } }));

    if (this.activeModal === targetModal) {
      this.activeModal = null;
    }
  }

  /**
   * Close a dynamically created modal
   */
  private closeDynamicModal(modal: HTMLElement): void {
    // Animate out
    modal.classList.remove('modal--visible');
    document.body.style.overflow = '';

    setTimeout(() => {
      modal.remove();
      this.dynamicModals.delete(modal);

      // If this was the active modal, clear it
      if (this.activeModal === modal) {
        this.activeModal = null;
        document.body.classList.remove('modal-open');
      }
    }, 300);
  }

  /**
   * Close all modals
   */
  closeAllModals(): void {
    // Close declarative modals
    document.querySelectorAll('[data-modal-container]').forEach((modal) => {
      const modalElement = modal as HTMLElement;
      modalElement.setAttribute('data-open', 'false');
      modalElement.setAttribute('aria-hidden', 'true');
    });

    // Remove dynamic modals
    this.dynamicModals.forEach((modal) => {
      modal.remove();
    });
    this.dynamicModals.clear();

    document.body.classList.remove('modal-open');
    this.activeModal = null;
  }

  /**
   * Trap focus within a modal
   */
  private trapFocus(element: HTMLElement): void {
    const focusableElements = element.querySelectorAll(
      'a[href], button, textarea, input[type="text"], input[type="radio"], input[type="checkbox"], select, [tabindex]:not([tabindex="-1"])'
    );

    if (focusableElements.length === 0) return;

    const firstFocusableElement = focusableElements[0] as HTMLElement;
    const lastFocusableElement = focusableElements[focusableElements.length - 1] as HTMLElement;

    const handleTabKey = (e: KeyboardEvent) => {
      if (e.key !== 'Tab') return;

      if (e.shiftKey) {
        if (document.activeElement === firstFocusableElement) {
          e.preventDefault();
          lastFocusableElement?.focus();
        }
      } else {
        if (document.activeElement === lastFocusableElement) {
          e.preventDefault();
          firstFocusableElement?.focus();
        }
      }
    };

    element.addEventListener('keydown', handleTabKey);
  }

  /**
   * Create a dynamic modal based on type
   */
  private createDynamicModal(modalId: string, modalType: string): void {
    console.log(
      '[ModalManager] createDynamicModal called with modalId:',
      modalId,
      'modalType:',
      modalType
    );

    // Check if modal already exists
    const existingModal = document.querySelector(
      `.modal[data-dynamic-id="${modalId}"]`
    ) as HTMLElement;
    console.log(
      '[ModalManager] Checking for existing modal:',
      `.modal[data-dynamic-id="${modalId}"]`,
      existingModal
    );
    if (existingModal) {
      console.log('[ModalManager] Modal already exists, returning early');
      return;
    }

    // Store the modal type mapping
    this.modalTypeMap.set(modalId, modalType);

    // Create new modal
    console.log('[ModalManager] Creating new modal');
    const modal = document.createElement('div');
    modal.className = 'modal modal--lead-magnet';
    modal.setAttribute('data-dynamic-id', modalId);
    console.log(
      '[ModalManager] Modal element created with className:',
      modal.className,
      'and data-dynamic-id:',
      modalId
    );

    const modalContent = this.getModalContent(modalType);
    console.log(
      '[ModalManager] Modal content for type',
      modalType,
      ':',
      modalContent ? 'found' : 'NOT FOUND'
    );
    if (!modalContent) {
      console.log('[ModalManager] No modal content found, returning early');
      return;
    }

    modal.innerHTML = modalContent;
    document.body.appendChild(modal);
    this.dynamicModals.add(modal);
    console.log('[ModalManager] Modal added to DOM and dynamicModals set');
  }

