import { useState, useCallback } from 'preact/hooks';
import { useModal } from './modal-context';

interface DynamicModal {
  id: string;
  type: string;
  data?: unknown;
}

export const useDynamicModals = () => {
  const { openModal } = useModal();
  const [modals, setModals] = useState<DynamicModal[]>([]);

  const createModal = useCallback(
    (id: string, type: string, data?: unknown) => {
      setModals((prev) => {
        // Check if modal already exists
        if (prev.some((modal) => modal.id === id)) {
          return prev;
        }
        return [...prev, { id, type, data }];
      });
      openModal(id);
    },
    [openModal]
  );

  const removeModal = useCallback((id: string) => {
    setModals((prev) => prev.filter((modal) => modal.id !== id));
  }, []);

  return { modals, createModal, removeModal };
};

import { useEffect, useRef } from 'preact/hooks';
import { useModal } from '../model/modal-context';

interface ModalProps {
  id: string;
  title: string;
  onClose?: () => void;
  children: import('preact').ComponentChildren;
}

export default function Modal({ id, title, onClose, children }: ModalProps) {
  const { activeModal, closeModal } = useModal();
  const modalRef = useRef<HTMLDivElement>(null);
  const isOpen = activeModal === id;

  // Handle ESC key
  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && isOpen) {
        handleClose();
      }
    };

    if (isOpen) {
      document.addEventListener('keydown', handleEsc);
      // Prevent body scroll when modal is open
      document.body.style.overflow = 'hidden';
    }

    return () => {
      document.removeEventListener('keydown', handleEsc);
      document.body.style.overflow = '';
    };
  }, [isOpen]);

  // Handle click outside
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (modalRef.current && !modalRef.current.contains(e.target as Node) && isOpen) {
        handleClose();
      }
    };

    if (isOpen) {
      document.addEventListener('mousedown', handleClickOutside);
    }

    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [isOpen]);

  const handleClose = () => {
    closeModal();
    if (onClose) onClose();
  };

  if (!isOpen) return null;

  return (
    <div class="modal modal--visible" ref={modalRef}>
      <div class="modal__overlay"></div>
      <div class="modal__container">
        <div class="modal__header">
          <h3 class="modal__title">{title}</h3>
          <button class="modal__close" onClick={handleClose}>
            &times;
          </button>
        </div>
        <div class="modal__body">{children}</div>
      </div>
    </div>
  );
}

import { useState } from 'preact/hooks';
import type { FormConfig, FormField } from '../../types/form';

interface Props {
  config: FormConfig;
  onSuccess?: () => void;
  onError?: (error: string) => void;
}

export default function Form({ config, onSuccess, onError }: Props) {
  const [formData, setFormData] = useState<{ [key: string]: string }>({});
  const [errors, setErrors] = useState<{ [key: string]: string }>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubmitted, setIsSubmitted] = useState(false);

  const { formId, formType, fields, submitText, endpoint } = config;

  const handleChange = (e: Event) => {
    const target = e.target as HTMLInputElement;
    if (!target) return;
    setFormData({
      ...formData,
      [target.name]: target.value,
    });

    // Clear error when user types
    if (errors[target.name]) {
      setErrors({
        ...errors,
        [target.name]: '',
      });
    }
  };

  const validate = (): boolean => {
    const newErrors: { [key: string]: string } = {};

    fields.forEach((field: FormField) => {
      if (field.required && !formData[field.name]) {
        newErrors[field.name] = field.validation?.message || 'Поле обязательно для заполнения';
      }

      // Add other validation rules based on field type
      if (
        field.type === 'email' &&
        formData[field.name] &&
        !isValidEmail(formData[field.name] || '')
      ) {
        newErrors[field.name] = 'Введите корректный email';
      }

      if (
        field.type === 'tel' &&
        formData[field.name] &&
        !isValidPhone(formData[field.name] || '')
      ) {
        newErrors[field.name] = 'Введите корректный телефон';
      }
    });

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: Event) => {
    e.preventDefault();
    const form = e.target as HTMLFormElement;
    if (!form) return;

    if (!validate()) return;

    setIsSubmitting(true);

    try {
      const response = await fetch(endpoint || '/api/form', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          ...formData,
          formType,
          formId,
          timestamp: new Date().toISOString(),
        }),
      });

      const result = await response.json();

      if (result.success) {
        setIsSubmitted(true);
        onSuccess?.();

        // Track analytics
        trackFormSubmission(formType, formId);

        // Reset form after 5 seconds
        setTimeout(() => {
          setFormData({});
          setIsSubmitted(false);
          setErrors({});
        }, 5000);
      } else {
        throw new Error(result.error || 'Ошибка отправки формы');
      }
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : 'Произошла ошибка. Попробуйте позже.';
      setErrors({ general: errorMessage });
      onError?.(errorMessage);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} class="space-y-4">
      {fields.map((field: FormField) => (
        <div class="form-field">
          <label
            for={`${formId}-${field.name}`}
            class="block text-sm font-medium text-gray-700 mb-1"
          >
            {field.label} {field.required && <span class="text-red-500">*</span>}
          </label>
          <input
            type={field.type}
            id={`${formId}-${field.name}`}
            name={field.name}
            value={formData[field.name] || ''}
            onInput={handleChange}
            class={`w-full px-4 py-2 border ${errors[field.name] ? 'border-red-500' : 'border-gray-300'} rounded-lg focus:ring-2 focus:ring-primary focus:border-transparent transition-colors`}
            placeholder={field.placeholder}
            required={field.required}
          />
          {errors[field.name] && (
            <span class="text-sm text-red-600 mt-1 block" role="alert">
              {errors[field.name]}
            </span>
          )}
        </div>
      ))}

      <button
        type="submit"
        disabled={isSubmitting}
        class="w-full py-3 px-6 bg-primary text-white rounded-lg hover:bg-primary-dark focus:outline-none focus:ring-2 focus:ring-primary focus:ring-offset-2 transition-colors duration-200 font-medium"
      >
        <span class="flex items-center justify-center">
          {isSubmitting ? 'Отправка...' : submitText}
          {isSubmitting && (
            <span class="ml-2">
              <svg
                class="animate-spin h-5 w-5 text-white"
                viewBox="0 0 20 20"
                aria-label="Загрузка"
              >
                <circle
                  cx="10"
                  cy="10"
                  r="8"
                  stroke="currentColor"
                  stroke-width="2"
                  fill="none"
                  stroke-linecap="round"
                />
              </svg>
            </span>
          )}
        </span>
      </button>

      {errors.general && (
        <div class="bg-red-50 border border-red-200 rounded-lg p-4 mt-2" role="alert">
          <p class="text-sm text-red-700">{errors.general}</p>
        </div>
      )}

      {isSubmitted && (
        <div
          class="bg-green-50 border border-green-200 rounded-lg p-4 mt-2"
          role="alert"
          aria-live="polite"
        >
          <div class="flex">
            <div class="flex-shrink-0">
              <svg class="h-5 w-5 text-green-400" viewBox="0 0 20 20" fill="currentColor">
                <path
                  fillRule="evenodd"
                  d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z"
                  clipRule="evenodd"
                />
              </svg>
            </div>
            <div class="ml-3">
              <h3 class="text-sm font-medium text-green-800">Заявка отправлена!</h3>
              <p class="text-sm text-green-700 mt-1">
                Мы свяжемся с вами в течение 15 минут для бесплатной консультации
              </p>
            </div>
          </div>
        </div>
      )}
    </form>
  );
}

// Validation helpers
const isValidEmail = (email: string): boolean => {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
};

const isValidPhone = (phone: string): boolean => {
  const phoneRegex = /^[\+]?[1-9][\d]{0,15}$/;
  return phoneRegex.test(phone.replace(/[\s\-\(\)]/g, ''));
};

// Analytics tracking
const trackFormSubmission = (formType: string, formId: string) => {
  if (typeof window !== 'undefined') {
    const win = window as typeof window & {
      gtag?: (command: string, ...args: unknown[]) => void;
      ym?: (id: number, command: string, ...args: unknown[]) => void;
    };

    // Google Analytics
    if (win.gtag) {
      win.gtag('event', 'form_submit', {
        form_type: formType,
        form_id: formId,
      });
    }

    // Yandex Metrika
    if (win.ym) {
      win.ym(94567890, 'reachGoal', 'form_submit', {
        form_type: formType,
        form_id: formId,
      });
    }
  }
};

import { useEffect, useRef } from 'preact/hooks';
import {
  initPhoneMask,
  initCurrencyMask,
  validateForm,
  validateField,
  showFieldError,
  clearFieldError,
} from '../../features/forms/model/form-utils';

interface FormProps {
  formId: string;
  formType: string;
  onSuccess?: () => void;
  onError?: (error: string) => void;
}

export default function Form({ formId, formType, onSuccess, onError }: FormProps) {
  const formRef = useRef<HTMLFormElement | null>(null);
  const maskInstances = useRef<Map<string, unknown>>(new Map());

  useEffect(() => {
    const form = document.getElementById(formId) as HTMLFormElement;
    if (!form) return;

    formRef.current = form;

    // Initialize phone mask
    initPhoneMask(form);

    // Initialize currency mask
    initCurrencyMask(form);

    // Form validation and submission
    const handleSubmit = async (e: Event) => {
      e.preventDefault();

      if (!validateForm(form)) {
        return;
      }

      await submitForm(form);
    };

    form.addEventListener('submit', handleSubmit);

    // Add input event listeners for real-time validation
    const inputs = form.querySelectorAll('input[required], input[data-validate]');
    inputs.forEach((input) => {
      input.addEventListener('blur', () => {
        const result = validateField(input as HTMLInputElement);
        if (!result.isValid) {
          showFieldError(input as HTMLInputElement, result.errorMessage);
        } else {
          clearFieldError(input as HTMLInputElement);
        }
      });
      input.addEventListener('input', () => clearFieldError(input as HTMLInputElement));
    });

    return () => {
      form.removeEventListener('submit', handleSubmit);
      // Clean up mask instances
      maskInstances.current.clear();
    };
  }, [formId, formType]);

  // Form submission
  const submitForm = async (form: HTMLFormElement) => {
    const submitButton = form.querySelector('.form__submit') as HTMLButtonElement;
    const successMessage = form.querySelector('.form__success-message') as HTMLElement;

    // Show loading state
    submitButton?.classList.add('loading');
    submitButton?.setAttribute('disabled', 'true');

    try {
      const formData = new FormData(form);
      formData.append('formType', formType);
      formData.append('formId', formId);

      // Add UTM parameters if present
      const urlParams = new URLSearchParams(window.location.search);
      ['utm_source', 'utm_medium', 'utm_campaign', 'utm_term', 'utm_content'].forEach((param) => {
        const value = urlParams.get(param);
        if (value) {
          formData.append(param, value);
        }
      });

      const response = await fetch('/api/form', {
        method: 'POST',
        body: formData,
      });

      const result = await response.json();

      if (result.success) {
        // Show success message
        form.style.display = 'none';
        successMessage?.classList.add('show');

        // Track event in analytics
        if (typeof window !== 'undefined') {
          const win = window as typeof window & {
            gtag?: (command: string, ...args: unknown[]) => void;
            ym?: (id: number, command: string, ...args: unknown[]) => void;
          };

          // Google Analytics
          if (win.gtag) {
            win.gtag('event', 'form_submit', {
              form_type: formType,
              form_id: formId,
            });
          }

          // Yandex Metrika
          if (win.ym) {
            win.ym(94567890, 'reachGoal', 'form_submit', {
              form_type: formType,
              form_id: formId,
            });
          }
        }

        // Call success callback
        if (onSuccess) {
          onSuccess();
        }

        // Reset form after 5 seconds
        setTimeout(() => {
          form.style.display = '';
          successMessage?.classList.remove('show');
          form.reset();
        }, 5000);
      } else {
        throw new Error(result.error || 'Ошибка отправки формы');
      }
    } catch (error) {
      console.error('Form submission error:', error);

      // Show error message
      const errorMessage =
        error instanceof Error ? error.message : 'Произошла ошибка. Попробуйте позже.';

      // Create or update error alert
      let errorAlert = form.querySelector('.form__alert') as HTMLElement;
      if (!errorAlert) {
        errorAlert = document.createElement('div');
        errorAlert.className = 'form__alert form__alert--error';
        form.insertBefore(errorAlert, form.firstChild);
      }
      errorAlert.textContent = errorMessage;
      errorAlert.style.display = 'block';

      // Hide error after 5 seconds
      setTimeout(() => {
        errorAlert.style.display = 'none';
      }, 5000);

      // Call error callback
      if (onError) {
        onError(errorMessage);
      }
    } finally {
      // Remove loading state
      submitButton?.classList.remove('loading');
      submitButton?.removeAttribute('disabled');
    }
  };

  return null; // This component doesn't render anything
}

import { useState } from 'preact/hooks';
import type { TeamMember } from '../../types/team';

interface Props {
  members: TeamMember[];
}

export default function TeamInteractive({ members }: Props) {
  const [activeMemberId, setActiveMemberId] = useState<string>(members[0]?.id || '');

  const handleTabChange = (memberId: string): void => {
    setActiveMemberId(memberId);
  };

  const handleArrowNavigation = (e: KeyboardEvent, currentIndex: number): void => {
    let newIndex: number | undefined;

    if (e.key === 'ArrowDown') {
      newIndex = Math.min(currentIndex + 1, members.length - 1);
    } else if (e.key === 'ArrowUp') {
      newIndex = Math.max(currentIndex - 1, 0);
    }

    if (newIndex !== undefined && newIndex !== currentIndex) {
      e.preventDefault();
      const memberId = members[newIndex]?.id;
      if (memberId) {
        setActiveMemberId(memberId);
      }
    }
  };

  const activeMember = members.find((member) => member.id === activeMemberId);

  return (
    <section class="py-16 md:py-24" id="team">
      <div class="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div class="text-center mb-12 md:mb-16">
