import { useEffect } from 'preact/hooks';

export interface FaqProps {
  data?: any;
  [key: string]: any;
}

export default function Faq(_props: FaqProps) {
  useEffect(() => {
    // FAQ accordion functionality
    const initializeFAQ = () => {
      const faqItems = document.querySelectorAll('[data-faq-item]');

      faqItems.forEach((item) => {
        const trigger = item.querySelector('[data-faq-trigger]') as HTMLElement;
        const content = item.querySelector('[data-faq-content]') as HTMLElement;

        if (!trigger || !content) return;

        // Ensure correct initial state
        item.classList.remove('faq__item--expanded');

        trigger.addEventListener('click', () => {
          const isOpen = trigger.getAttribute('aria-expanded') === 'true';

          // Close all other items
          faqItems.forEach((otherItem) => {
            if (otherItem !== item) {
              const otherTrigger = otherItem.querySelector('[data-faq-trigger]') as HTMLElement;
              const otherContent = otherItem.querySelector('[data-faq-content]') as HTMLElement;

              if (otherTrigger && otherContent) {
                otherTrigger.setAttribute('aria-expanded', 'false');
                otherContent.setAttribute('aria-hidden', 'true');
                otherItem.classList.remove('faq__item--expanded');
                // Remove inline style for closing
                otherContent.style.maxHeight = '';
              }
            }
          });

          // Toggle current item
          if (isOpen) {
            // Close
            trigger.setAttribute('aria-expanded', 'false');
            content.setAttribute('aria-hidden', 'true');
            item.classList.remove('faq__item--expanded');
            // Remove inline style for closing
            content.style.maxHeight = '';
          } else {
            // Open
            trigger.setAttribute('aria-expanded', 'true');
            content.setAttribute('aria-hidden', 'false');
            item.classList.add('faq__item--expanded');
            // Set max height for animation
            content.style.maxHeight = content.scrollHeight + 'px';

            // Recalculate height after transition for dynamic content
            setTimeout(() => {
              if (trigger.getAttribute('aria-expanded') === 'true' && content) {
                content.style.maxHeight = content.scrollHeight + 'px';
              }
            }, 300);
          }
        });
      });
    };

    // Handle window resize to adjust opened accordions
    let resizeTimer: NodeJS.Timeout;
    const handleResize = () => {
      clearTimeout(resizeTimer);
      resizeTimer = setTimeout(() => {
        const faqItems = document.querySelectorAll('[data-faq-item]');
        faqItems.forEach((item) => {
          const trigger = item.querySelector('[data-faq-trigger]') as HTMLElement;
          const content = item.querySelector('[data-faq-content]') as HTMLElement;

          if (trigger?.getAttribute('aria-expanded') === 'true' && content) {
            content.style.maxHeight = content.scrollHeight + 'px';
          }
        });
      }, 250);
    };

    // Initialize when DOM is ready
    if (document.readyState === 'loading') {
      document.addEventListener('DOMContentLoaded', initializeFAQ);
    } else {
      initializeFAQ();
    }

    // Add resize listener
    window.addEventListener('resize', handleResize);

    return () => {
      // Cleanup
      window.removeEventListener('resize', handleResize);
    };
  }, []);

  return null;
}

import { useEffect } from 'preact/hooks';

export default function LeadMagnetsLogic() {
  useEffect(() => {
    // Button click handlers
    const buttons = document.querySelectorAll(
      '.lead-card__button[data-modal], .lead-magnets__cta-button[data-modal]'
    );

    const handleButtonClick = (e: Event) => {
      e.preventDefault();
      const button = e.currentTarget as HTMLElement;
      const modalType = button.getAttribute('data-modal');
      const trackEvent = button.getAttribute('data-track');

      if (modalType) {
        openModal(modalType);
      }

      if (trackEvent) {
        trackAnalytics(trackEvent, { modal_type: modalType });
      }
    };

    buttons.forEach((button) => {
      button.addEventListener('click', handleButtonClick);
    });

    // Modal functionality
    function openModal(modalType: string) {
      const modal = createModal(modalType);
      if (!modal) return;

      document.body.appendChild(modal);
      document.body.style.overflow = 'hidden';

      // Animate in
      requestAnimationFrame(() => {
        modal.classList.add('modal--visible');
      });

      // Setup close handlers
      const closeBtn = modal.querySelector('[data-modal-close]');
      const overlay = modal.querySelector('.modal__overlay');

      const closeModal = () => {
        modal.classList.remove('modal--visible');
        document.body.style.overflow = '';
        setTimeout(() => {
          modal.remove();
        }, 300);
      };

      if (closeBtn) {
        closeBtn.addEventListener('click', closeModal);
      }

      if (overlay) {
        overlay.addEventListener('click', closeModal);
      }

      // Escape key handler
      const handleEscape = (e: KeyboardEvent) => {
        if (e.key === 'Escape') {
          closeModal();
          document.removeEventListener('keydown', handleEscape);
        }
      };

      document.addEventListener('keydown', handleEscape);

      // Form handler
      const form = modal.querySelector('form');
      if (form) {
        form.addEventListener('submit', async (e) => {
          e.preventDefault();
          await handleFormSubmit(form, modalType);
        });
      }

      // Range input handler for calculator
      const rangeInput = modal.querySelector('input[type="range"]');
      if (rangeInput) {
        const display = modal.querySelector('#debt-amount-display');
        rangeInput.addEventListener('input', (e) => {
          const value = parseInt((e.target as HTMLInputElement).value);
          if (display) {
            display.textContent = formatCurrency(value);
          }
        });
      }
    }

    function createModal(modalType: string): HTMLElement | null {
      const modal = document.createElement('div');
