import { useEffect } from 'preact/hooks';
import { useModal } from '@features/modals/model/modal-context';
import { useDynamicModals } from '@features/modals/model/use-dynamic-modals';

export default function ModalManager() {
  const { openModal, closeModal } = useModal();
  const { createModal } = useDynamicModals();

  useEffect(() => {
    console.log('[ModalManager] Initializing with hooks');

    // Setup event delegation for modal triggers
    const handleTriggerClick = (e: Event) => {
      const target = e.target as HTMLElement;
      const trigger = target.closest('[data-modal]') as HTMLElement;

      if (trigger) {
        e.preventDefault();
        const modalId = trigger.getAttribute('data-modal');
        const modalType = trigger.getAttribute('data-modal-type');

        if (modalId) {
          if (modalType) {
            // Create dynamic modal
            createModal(modalId, modalType);
          } else {
            // Open existing modal
            openModal(modalId);
          }
        }
      }

      // Handle close buttons
      const closeBtn = target.closest('[data-modal-close]') as HTMLElement;
      if (closeBtn) {
        e.preventDefault();
        closeModal();
      }
    };

    // Setup hash change handling for direct modal opening
    const checkHashForModal = () => {
      const hash = window.location.hash.replace('#', '');
      if (hash.startsWith('modal-')) {
        const modalId = hash.replace('modal-', '');
        openModal(modalId);
      }
    };

    // Add event listeners
    document.addEventListener('click', handleTriggerClick);
    window.addEventListener('hashchange', checkHashForModal);

    // Check for hash on initial load
    checkHashForModal();

    // Setup public API
    (window as any).modalManager = {
      open: openModal,
      close: closeModal,
      closeAll: () => {
        closeModal();
        // Additional cleanup if needed
      },
    };

    console.log('[ModalManager] Initialization completed with hooks');

    // Cleanup function
    return () => {
      console.log('[ModalManager] Cleaning up');
      document.removeEventListener('click', handleTriggerClick);
      window.removeEventListener('hashchange', checkHashForModal);
      delete (window as any).modalManager;
    };
  }, []);

  return null;
}

import { useEffect } from 'preact/hooks';

interface ScrollAnimationsProps {
  offset?: number;
  duration?: number;
  once?: boolean;
  mirror?: boolean;
  anchorPlacement?: string;
}

/**
 * ScrollAnimations Component
 * Handles scroll-triggered animations for elements with data-aos attributes
 * Based on AOS (Animate On Scroll) library concepts
 */
export default function ScrollAnimations({
  offset = 120,
  duration = 800,
  once = false,
  mirror = false,
}: ScrollAnimationsProps) {
  // anchorPlacement parameter available but unused in current implementation
  useEffect(() => {
    // Get all elements with data-aos attribute
    const animatedElements = document.querySelectorAll('[data-aos]');

    if (animatedElements.length === 0) return;

    // IntersectionObserver options
    const observerOptions = {
      root: null,
      rootMargin: `-${offset}px 0px`,
      threshold: 0.1,
    };

    // Track which elements have been animated
    const animatedSet = new Set<Element>();

    // IntersectionObserver callback
    const observerCallback = (entries: IntersectionObserverEntry[]) => {
      entries.forEach((entry) => {
        const element = entry.target as HTMLElement;

        if (entry.isIntersecting) {
          // Element is visible - add animation
          element.classList.add('aos-animated');
          animatedSet.add(element);

          // If once is true, stop observing this element
          if (once) {
            observer.unobserve(element);
          }
        } else if (!once || mirror) {
          // Element is not visible and we should remove animation
          if (animatedSet.has(element)) {
            element.classList.remove('aos-animated');
            animatedSet.delete(element);
          }
        }
      });
    };

    // Create observer
    const observer = new IntersectionObserver(observerCallback, observerOptions);

    // Observe all elements
    animatedElements.forEach((element) => {
      // Apply custom duration if specified on element
      const customDuration = element.getAttribute('data-aos-duration');
      if (customDuration) {
        (element as HTMLElement).style.transitionDuration = `${customDuration}ms`;
      } else {
        (element as HTMLElement).style.transitionDuration = `${duration}ms`;
      }

      // Apply custom delay if specified on element
      const customDelay = element.getAttribute('data-aos-delay');
      if (customDelay) {
        (element as HTMLElement).style.transitionDelay = `${customDelay}ms`;
      }

      // Apply custom easing if specified on element
      const customEasing = element.getAttribute('data-aos-easing');
      if (customEasing) {
        (element as HTMLElement).style.transitionTimingFunction = customEasing;
      }

      // Start observing
      observer.observe(element);
    });

    // Cleanup function
    return () => {
      observer.disconnect();
    };
  }, [offset, duration, once, mirror]);

  // This component doesn't render anything
  return null;
}

/**
 * Utility function to trigger re-initialization of animations
 * Useful after dynamic content is added to the page
 */
export function refreshScrollAnimations() {
  const event = new CustomEvent('aos:refresh');
  window.dispatchEvent(event);
}

/**
 * Utility function to programmatically trigger animation on an element
 */
export function animateElement(element: HTMLElement) {
  if (element.hasAttribute('data-aos')) {
    element.classList.add('aos-animated');
  }
}

/**
 * Utility function to reset animation on an element
 */
export function resetAnimation(element: HTMLElement) {
  if (element.hasAttribute('data-aos')) {
    element.classList.remove('aos-animated');
  }
}

import { useEffect, useRef, useState } from 'preact/hooks';

// Declare gtag global function

interface StickyPanelProps {
  delay?: number;
  scrollThreshold?: number;
  cookieDays?: number;
}

export default function StickyPanel({
  delay = 5000,
  scrollThreshold = 300,
  cookieDays = 1,
}: StickyPanelProps) {
  const [isVisible, setIsVisible] = useState(false);
  const [hasBeenShown, setHasBeenShown] = useState(false);
  const timerRef = useRef<NodeJS.Timeout | null>(null);
  const countdownRef = useRef<NodeJS.Timeout | null>(null);
  const cookieName = 'sticky_panel_closed';

  // Cookie utilities
  const getCookie = (name: string): string | null => {
    const value = `; ${document.cookie}`;
    const parts = value.split(`; ${name}=`);
    if (parts.length === 2) {
      return parts.pop()?.split(';').shift() || null;
    }
    return null;
  };

  const setCookie = (name: string, value: string, days: number) => {
    const expires = new Date();
    expires.setTime(expires.getTime() + days * 24 * 60 * 60 * 1000);
    document.cookie = `${name}=${value};expires=${expires.toUTCString()};path=/`;
  };

  // Handle countdown timer
  const startCountdown = () => {
    const panel = document.querySelector('[data-sticky-panel]');
    if (!panel) return;

    const timerElement = panel.querySelector('[data-timer]');
    if (!timerElement) return;

    const targetDate = timerElement.getAttribute('data-timer');
    if (!targetDate) return;

    const target = new Date(targetDate).getTime();

    const updateTimer = () => {
      const now = new Date().getTime();
      const distance = target - now;

      if (distance < 0) {
        hide();
        return;
      }

      const days = Math.floor(distance / (1000 * 60 * 60 * 24));
      const hours = Math.floor((distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
      const minutes = Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60));

      const daysEl = timerElement.querySelector('[data-days]');
      const hoursEl = timerElement.querySelector('[data-hours]');
      const minutesEl = timerElement.querySelector('[data-minutes]');

      if (daysEl) daysEl.textContent = String(days).padStart(2, '0');
      if (hoursEl) hoursEl.textContent = String(hours).padStart(2, '0');
      if (minutesEl) minutesEl.textContent = String(minutes).padStart(2, '0');
    };

    updateTimer();
    countdownRef.current = setInterval(updateTimer, 60000); // Update every minute
  };

  // Show panel
  const show = () => {
    if (isVisible || hasBeenShown) return;

    const panel = document.querySelector('[data-sticky-panel]');
    if (!panel) return;

    panel.removeAttribute('hidden');
    panel.classList.add('sticky-panel--visible');

    requestAnimationFrame(() => {
      panel.classList.add('sticky-panel--animate');
    });

    setIsVisible(true);
    setHasBeenShown(true);

    // Start countdown if timer exists
    startCountdown();

    // Track analytics event
    if (typeof window.gtag !== 'undefined') {
      window.gtag('event', 'view', {
        event_category: 'StickyPanel',
        event_label: 'panel_shown',
      });
    }
  };

  // Hide panel
  const hide = () => {
    const panel = document.querySelector('[data-sticky-panel]');
    if (!panel) return;

    panel.classList.remove('sticky-panel--animate');
    panel.classList.remove('sticky-panel--visible');

    setTimeout(() => {
      panel.setAttribute('hidden', '');
    }, 300);

    setIsVisible(false);

    // Set cookie
    setCookie(cookieName, 'true', cookieDays);

    // Clear timers
    if (countdownRef.current) {
      clearInterval(countdownRef.current);
    }

    // Track analytics event
    if (typeof window.gtag !== 'undefined') {
      window.gtag('event', 'close', {
        event_category: 'StickyPanel',
        event_label: 'panel_closed',
      });
    }
  };

  useEffect(() => {
    // Check if panel was previously closed
    if (getCookie(cookieName)) {
      return;
    }

    const panel = document.querySelector('[data-sticky-panel]');
    if (!panel) return;

    // Setup close button
    const closeBtn = panel.querySelector('[data-sticky-close]');
    if (closeBtn) {
      closeBtn.addEventListener('click', hide);
    }

    // Setup CTA buttons
    const ctaButtons = panel.querySelectorAll('[data-modal]');
    ctaButtons.forEach((btn) => {
      btn.addEventListener('click', (e) => {
        const target = e.currentTarget as HTMLElement;
        const modalName = target.getAttribute('data-modal');
        const trackEvent = target.getAttribute('data-track');

        // Track event
        if (trackEvent && typeof window.gtag !== 'undefined') {
          window.gtag('event', 'click', {
            event_category: 'StickyPanel',
            event_label: trackEvent,
          });
        }

        // Trigger modal
        if (modalName) {
          window.dispatchEvent(
            new CustomEvent('open-modal', {
              detail: { modal: modalName },
            })
          );
        }

        // Hide panel
        hide();
      });
    });

    // Delay trigger
    timerRef.current = setTimeout(() => {
      if (!hasBeenShown) {
        show();
      }
    }, delay);

    // Scroll trigger
    let scrollTimer: NodeJS.Timeout;
    const handleScroll = () => {
      clearTimeout(scrollTimer);
      scrollTimer = setTimeout(() => {
        if (!hasBeenShown && window.scrollY > scrollThreshold) {
          show();
        }
      }, 100);
    };

    window.addEventListener('scroll', handleScroll);

    // Cleanup
    return () => {
      if (timerRef.current) {
        clearTimeout(timerRef.current);
      }
      if (countdownRef.current) {
        clearInterval(countdownRef.current);
      }
      window.removeEventListener('scroll', handleScroll);

      if (closeBtn) {
        closeBtn.removeEventListener('click', hide);
      }
    };
  }, [delay, scrollThreshold, cookieDays, hasBeenShown]);

  return null; // This component only handles logic, no UI
}

/**
 * Analytics module for tracking user interactions and page views
 */

// The gtag interface is already declared in social-links.tsx
// No need to redeclare it here

/**
 * Initialize analytics tracking
 */
export function initAnalytics(): void {
  // Initialize Google Analytics if available
  if (typeof window !== 'undefined' && typeof window.gtag === 'function') {
    console.log('Analytics initialized');

    // Track initial page view
    trackPageView(window.location.pathname + window.location.search);
  } else {
    // Fallback analytics initialization
    console.log('Analytics not available, using fallback tracking');
  }
}

/**
 * Track a page view
 * @param url - The URL to track
 * @param title - The page title
 */
export function trackPageView(url: string = '', title: string = ''): void {
  if (typeof window !== 'undefined' && typeof window.gtag === 'function') {
    window.gtag('config', import.meta.env.PUBLIC_GA_MEASUREMENT_ID || 'GA_MEASUREMENT_ID', {
      page_path: url,
      page_title: title,
    });
  } else {
    console.log(`Page view tracked: ${url || window.location.pathname}`);
  }
}

/**
 * Track a custom event
 * @param action - The action name
 * @param category - The event category
 * @param label - Optional label
 * @param value - Optional value
 */
export function trackEvent(action: string, category: string, label?: string, value?: number): void {
  if (typeof window !== 'undefined' && typeof window.gtag === 'function') {
    window.gtag('event', action, {
      event_category: category,
      event_label: label,
      value: value,
    });
  } else {
    console.log(`Event tracked: ${action} in ${category}${label ? ` (label: ${label})` : ''}`);
  }
}

/**
 * Track an exception
 * @param description - Description of the error
 * @param fatal - Whether the error was fatal
 */
export function trackException(description: string, fatal: boolean = false): void {
  if (typeof window !== 'undefined' && typeof window.gtag === 'function') {
    window.gtag('event', 'exception', {
      description: description,
      fatal: fatal,
    });
  } else {
    console.error(`Exception tracked: ${description}, Fatal: ${fatal}`);
  }
}

// Bitrix Callback Widget Logic
export class BitrixCallback {
  constructor(bitrixWebhookUrl, sitePhone) {
    // If no webhook URL, don't initialize
    if (!bitrixWebhookUrl) {
      console.warn('BitrixCallback: No webhook URL provided, widget will not function');
      return;
    }

    this.widget = document.querySelector('.bitrix-callback');
    this.button = document.querySelector('.bitrix-callback__button');
    this.popup = document.querySelector('.bitrix-callback__popup');
    this.closeBtn = document.querySelector('.bitrix-callback__close');
    this.form = document.querySelector('.bitrix-callback__form');
    this.successState = document.querySelector('.bitrix-callback__success');
    this.webhookUrl = bitrixWebhookUrl;
    this.sitePhone = sitePhone;

    this.init();
  }

  init() {
    // If no webhook URL, don't initialize
    if (!this.webhookUrl) {
      return;
    }

    // Show widget after hero section
    this.setupVisibilityTrigger();

    // Event listeners
    this.button?.addEventListener('click', () => this.togglePopup());
    this.closeBtn?.addEventListener('click', () => this.closePopup());
    this.form?.addEventListener('submit', (e) => this.handleSubmit(e));

    // Close popup on outside click
    document.addEventListener('click', (e) => {
      if (!this.widget?.contains(e.target)) {
        this.closePopup();
      }
    });

    // Phone mask
    this.setupPhoneMask();

    // Form validation
    this.setupValidation();
  }

  setupVisibilityTrigger() {
    // Find hero section
    const heroSection = document.querySelector('#hero, .hero, section:first-of-type');

    if (heroSection) {
      const observer = new IntersectionObserver(
        (entries) => {
          entries.forEach((entry) => {
            if (entry.intersectionRatio < 0.1) {
              // Hero section is mostly out of view
              this.showWidget();
            }
          });
        },
        {
          threshold: [0, 0.1, 0.5, 1],
        }
      );

      observer.observe(heroSection);
    } else {
      // Fallback: show after scroll
      let scrolled = false;
      window.addEventListener('scroll', () => {
        if (!scrolled && window.scrollY > 300) {
          scrolled = true;
          this.showWidget();
        }
      });
    }
  }

  showWidget() {
    this.widget?.classList.add('bitrix-callback--visible');
    // Widget is now fixed to bottom-right, no need to adjust position
  }

  togglePopup() {
    const isActive = this.popup?.classList.contains('bitrix-callback__popup--active');
    if (isActive) {
      this.closePopup();
    } else {
      this.openPopup();
    }
  }

  openPopup() {
    this.popup?.classList.add('bitrix-callback__popup--active');

    // Analytics
    if (typeof gtag !== 'undefined') {
      gtag('event', 'callback_widget_opened', {
        event_category: 'engagement',
        event_label: 'bitrix_callback',
      });
    }
  }

  closePopup() {
    this.popup?.classList.remove('bitrix-callback__popup--active');
  }

  setupPhoneMask() {
    const phoneInput = document.getElementById('callback-phone');
    if (!phoneInput) return;

    phoneInput.addEventListener('input', (e) => {
      let value = e.target.value.replace(/\D/g, '');

      if (value.length > 0) {
        if (value[0] === '7' || value[0] === '8') {
          value = value.substring(1);
        }

        let formatted = '+7';
        if (value.length > 0) {
          formatted += ' (' + value.substring(0, 3);
        }
        if (value.length >= 4) {
          formatted += ') ' + value.substring(3, 6);
        }
        if (value.length >= 7) {
          formatted += '-' + value.substring(6, 8);
        }
        if (value.length >= 9) {
          formatted += '-' + value.substring(8, 10);
        }

        e.target.value = formatted;
      }
    });
  }

  setupValidation() {
    const nameInput = document.getElementById('callback-name');
    const phoneInput = document.getElementById('callback-phone');

    nameInput?.addEventListener('blur', () => {
      if (nameInput.value.trim().length < 2) {
        this.showError(nameInput, 'Введите ваше имя');
      } else {
        this.hideError(nameInput);
      }
    });

    phoneInput?.addEventListener('blur', () => {
      const cleaned = phoneInput.value.replace(/\D/g, '');
      if (cleaned.length < 11) {
        this.showError(phoneInput, 'Введите корректный номер телефона');
      } else {
        this.hideError(phoneInput);
      }
    });
  }

  showError(input, message) {
    const error = input.nextElementSibling;
    if (error) {
      error.textContent = message;
      error.classList.add('bitrix-callback__error--visible');
    }
    input.style.borderColor = '#ef4444';
  }

  hideError(input) {
    const error = input.nextElementSibling;
    if (error) {
      error.classList.remove('bitrix-callback__error--visible');
    }
    input.style.borderColor = '';
  }

  async handleSubmit(e) {
    e.preventDefault();

    // If no webhook URL, don't submit
    if (!this.webhookUrl) {
      console.error('BitrixCallback: No webhook URL provided, cannot submit form');
      return;
    }

    const formData = new FormData(this.form);
    const data = {
      name: formData.get('name'),
      phone: formData.get('phone'),
      callTime: formData.get('callTime'),
      source: 'callback_widget',
      page: window.location.pathname,
    };

    // Validate
    if (!data.name || data.name.trim().length < 2) {
      this.showError(document.getElementById('callback-name'), 'Введите ваше имя');
      return;
    }

    const cleanedPhone = data.phone.replace(/\D/g, '');
    if (cleanedPhone.length < 11) {
      this.showError(
        document.getElementById('callback-phone'),
        'Введите корректный номер телефона'
      );
      return;
    }

    // Show loading state
    const submitBtn = this.form.querySelector('.bitrix-callback__submit');
    const submitText = submitBtn?.querySelector('.bitrix-callback__submit-text');
    const submitLoader = submitBtn?.querySelector('.bitrix-callback__submit-loader');

    if (submitBtn) submitBtn.disabled = true;
    if (submitText) submitText.style.display = 'none';
    if (submitLoader) submitLoader.style.display = 'block';

    try {
      // Send to Bitrix24
      if (this.webhookUrl) {
        await this.sendToBitrix24(data);
      }

      // Show success state
      this.showSuccess();

      // Analytics
      if (typeof gtag !== 'undefined') {
        gtag('event', 'callback_form_submitted', {
          event_category: 'lead',
          event_label: 'bitrix_callback',
        });
      }

      // Reset and close after delay
      setTimeout(() => {
        this.closePopup();
        this.form.reset();
        this.hideSuccess();
      }, 3000);
    } catch (error) {
      console.error('Error submitting callback form:', error);
      alert(`Произошла ошибка. Пожалуйста, позвоните нам: ${this.sitePhone}`);
    } finally {
      if (submitBtn) submitBtn.disabled = false;
      if (submitText) submitText.style.display = 'block';
      if (submitLoader) submitLoader.style.display = 'none';
    }
  }

  async sendToBitrix24(data) {
    // If no webhook URL, don't send
    if (!this.webhookUrl) {
      throw new Error('No webhook URL provided');
    }

    // Create lead in Bitrix24
    const leadData = {
      TITLE: `Обратный звонок: ${data.name}`,
      NAME: data.name,
      PHONE: [{ VALUE: data.phone, VALUE_TYPE: 'WORK' }],
      SOURCE_ID: 'WEB',
      SOURCE_DESCRIPTION: `Виджет обратного звонка - ${data.page}`,
      COMMENTS: `Желаемое время звонка: ${this.getCallTimeText(data.callTime)}`,
      UF_CRM_1234567890: data.callTime, // Custom field for call time
    };

    const response = await fetch(`${this.webhookUrl}crm.lead.add`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        fields: leadData,
        params: { REGISTER_SONET_EVENT: 'Y' },
      }),
    });

    if (!response.ok) {
      throw new Error('Failed to create lead in Bitrix24');
    }

    return response.json();
  }

  getCallTimeText(value) {
    const times = {
      now: 'Сейчас',
      '15min': 'Через 15 минут',
      '30min': 'Через 30 минут',
      '1hour': 'Через час',
      morning: 'Утром (9:00-12:00)',
      afternoon: 'Днем (12:00-18:00)',
      evening: 'Вечером (18:00-21:00)',
    };
    return times[value] || value;
  }

  showSuccess() {
    if (this.form) this.form.style.display = 'none';
    if (this.successState) this.successState.style.display = 'block';
  }

  hideSuccess() {
    if (this.form) this.form.style.display = 'flex';
    if (this.successState) this.successState.style.display = 'none';
  }
}

// Initialize when DOM is ready
export function initBitrixCallback(bitrixWebhookUrl, sitePhone) {
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', () => {
      new BitrixCallback(bitrixWebhookUrl, sitePhone);
    });
  } else {
    // DOM is already ready
    new BitrixCallback(bitrixWebhookUrl, sitePhone);
  }
}

